#include <bits/stdc++.h>
using namespace std;

int n, k, l[100005], maxn = INT_MIN;

bool check(int x) {
    int cnt = 0;
    for (int i = 0; i < n; i++) {
        // if (l[i] % x) return false;
        cnt += l[i] / x;
    }
    return (cnt >= k);
}

int find() {
    int l = 0, r = maxn;
    int mid = (l + r + 1) >> 1;
    while (l < r) {
        if (check(mid)) {
            l = mid;
        }
        else {
            r = mid - 1;
        }
        mid = (l + r + 1) >> 1;
    }
    return mid;
}

int main() {
    cin >> n >> k;
    for (int i = 0; i < n; i++) {
        double t;
        cin >> t;
        l[i] = t * 100;
        maxn = max(maxn, l[i]);
    }
    printf("%.2f", find() / 100.0);
    return 0;
}
